#!/usr/bin/env python3
"""
bootstrap_glycan_pulldown_v3.py -- Complete glycan pulldown + realization + ATHENA pipeline.

Supersedes all prior pulldown bootstraps.

Deploys 12 files:
  glycan/parameters_v23.py (3326 bytes)
  glycan/contact_maps.py (12084 bytes)
  glycan/click_site_predictor.py (14456 bytes)
  glycan/bead_linker_design.py (21828 bytes)
  glycan/pulldown_selector.py (21677 bytes)
  glycan/realization_ranker.py (30920 bytes)
  glycan/athena_staple_spec.py (19723 bytes)
  glycan/tests/test_click_site.py (9349 bytes)
  glycan/tests/test_bead_linker.py (9131 bytes)
  glycan/tests/test_pulldown_selector.py (13393 bytes)
  glycan/tests/test_realization_ranker.py (8389 bytes)
  glycan/tests/test_athena_staple_spec.py (8372 bytes)

Depends on: bootstrap_suprabank_ingest + bootstrap_suprabank_refit.
Apply BEFORE bootstrap_glycan_g2g5.py.
"""

import base64, os, sys

FILES = {
    'glycan/parameters_v23.py': '',
    'glycan/contact_maps.py': '',
    'glycan/click_site_predictor.py': '',
    'glycan/bead_linker_design.py': '',
    'glycan/pulldown_selector.py': '',
    'glycan/realization_ranker.py': '',
    'glycan/athena_staple_spec.py': '',
    'glycan/tests/test_click_site.py': '',
    'glycan/tests/test_bead_linker.py': '',
    'glycan/tests/test_pulldown_selector.py': '',
    'glycan/tests/test_realization_ranker.py': '',
    'glycan/tests/test_athena_staple_spec.py': '',
}


def find_root():
    d = os.path.abspath(os.getcwd())
    for _ in range(5):
        if os.path.isfile(os.path.join(d, "core", "universal_schema.py")):
            return d
        parent = os.path.dirname(d)
        if parent == d:
            break
        d = parent
    d = os.path.abspath(os.path.join(os.getcwd(), ".."))
    if os.path.isfile(os.path.join(d, "core", "universal_schema.py")):
        return d
    print("ERROR: Cannot find MABE repo root.")
    sys.exit(1)


def main():
    root = find_root()
    print(f"MABE root: {root}")
    print()
    for relpath, b64data in FILES.items():
        fullpath = os.path.join(root, relpath)
        os.makedirs(os.path.dirname(fullpath), exist_ok=True)
        content = base64.b64decode(b64data).decode("utf-8")
        with open(fullpath, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"  written: {relpath}")
    print()
    print(f"Bootstrap complete: {len(FILES)} files written.")
    print("Apply bootstrap_glycan_g2g5.py AFTER this bootstrap.")


if __name__ == "__main__":
    main()